c_run(&self) -> Result<serde_json::Value> {
        let resp = self
            .client
            .post(format!("{}/v1/gc/run", self.base_url))
            .send()
            .await?
            .error_for_status()?;
        Ok(resp.json().await?)
    }
pub async fn gc_history(&self) -> Result<serde_json::Value> {
        let resp = self
            .client
            .get(format!("{}/v1/gc/history", self.base_url))
            .send()
            .await?
            .error_for_status()?;
        Ok(resp.json().await?)
    }
